const results = [];
const seenLinks = new Set();

const addResult = (link, title, snippet) => {
  if (link && link.includes('linkedin.com/') && !seenLinks.has(link)) {
    seenLinks.add(link);
    results.push({ 
      json: { 
        title: title || "New LinkedIn Post", 
        link: link, 
        snippet: snippet || title || "No context available" 
      } 
    });
  }
};

// 1. Process Organic Results
const organic = $node["SerpApi"].json.organic_results;
if (organic && Array.isArray(organic)) {
  organic.forEach(res => {
    addResult(res.link, res.title, res.snippet);
  });
}

// 2. Process Perspectives (The feature you found!)
const perspectives = $node["SerpApi"].json.perspectives;
if (perspectives && Array.isArray(perspectives)) {
  perspectives.forEach(res => {
    const link = res.link || res.link_url || res.url;
    addResult(link, res.title, res.snippet || res.title);
  });
}

return results.slice(0, 3); // Returns top 3 unique posts
